{
  "name": "WealthTrack Pro",
  "description": "A professional-grade stock portfolio management application to track transactions, inventory, and dividend income with AI-powered insights and interactive dashboards."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum TransactionType {
  BUY = 'BUY',
  SELL = 'SELL'
}

export interface Transaction {
  id: string;
  date: string;
  ticker: string;
  type: TransactionType;
  quantity: number;
  price: number;
  fees: number;
  notes?: string;
}

export interface Dividend {
  id: string;
  date: string;
  ticker: string;
  amount: number;
  notes?: string;
}

export interface Holding {
  ticker: string;
  quantity: number;
  averageCost: number;
  totalInvested: number;
}

export interface PortfolioStats {
  totalInvested: number;
  totalDividend: number;
  holdingCount: number;
  topHolding: string;
}

import React, { useState, useEffect, useMemo } from 'react';
import { HashRouter, Routes, Route, Link, useLocation } from 'react-router-dom';
import { 
  LayoutDashboard, 
  ArrowLeftRight, 
  Wallet, 
  PiggyBank, 
  PlusCircle, 
  Menu, 
  X,
  TrendingUp,
  BrainCircuit
} from 'lucide-react';
import Dashboard from './components/Dashboard';
import Transactions from './components/Transactions';
import Portfolio from './components/Portfolio';
import Dividends from './components/Dividends';
import AIInsights from './components/AIInsights';
import { Transaction, Dividend, Holding, TransactionType } from './types';

// Initial Mock Data
const INITIAL_TRANSACTIONS: Transaction[] = [
  { id: '1', date: '2023-01-15', ticker: 'AAPL', type: TransactionType.BUY, quantity: 10, price: 145.00, fees: 5 },
  { id: '2', date: '2023-03-10', ticker: 'MSFT', type: TransactionType.BUY, quantity: 5, price: 250.00, fees: 5 },
  { id: '3', date: '2023-06-20', ticker: 'AAPL', type: TransactionType.BUY, quantity: 5, price: 180.00, fees: 5 },
  { id: '4', date: '2024-01-12', ticker: 'TSLA', type: TransactionType.BUY, quantity: 20, price: 220.00, fees: 10 },
  { id: '5', date: '2024-05-05', ticker: 'NVDA', type: TransactionType.BUY, quantity: 15, price: 850.00, fees: 15 },
];

const INITIAL_DIVIDENDS: Dividend[] = [
  { id: 'd1', date: '2023-02-15', ticker: 'AAPL', amount: 2.30 },
  { id: 'd2', date: '2023-05-15', ticker: 'AAPL', amount: 2.40 },
  { id: 'd3', date: '2023-08-15', ticker: 'AAPL', amount: 2.40 },
  { id: 'd4', date: '2023-11-15', ticker: 'AAPL', amount: 2.40 },
  { id: 'd5', date: '2024-02-15', ticker: 'AAPL', amount: 2.50 },
];

const SidebarItem = ({ to, icon: Icon, label, active }: { to: string, icon: any, label: string, active: boolean }) => (
  <Link
    to={to}
    className={`flex items-center space-x-3 px-4 py-3 rounded-lg transition-colors ${
      active 
        ? 'bg-blue-600 text-white shadow-lg shadow-blue-200' 
        : 'text-slate-600 hover:bg-slate-100'
    }`}
  >
    <Icon size={20} />
    <span className="font-medium">{label}</span>
  </Link>
);

const AppContent = () => {
  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('wt_transactions');
    return saved ? JSON.parse(saved) : INITIAL_TRANSACTIONS;
  });

  const [dividends, setDividends] = useState<Dividend[]>(() => {
    const saved = localStorage.getItem('wt_dividends');
    return saved ? JSON.parse(saved) : INITIAL_DIVIDENDS;
  });

  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const location = useLocation();

  useEffect(() => {
    localStorage.setItem('wt_transactions', JSON.stringify(transactions));
    localStorage.setItem('wt_dividends', JSON.stringify(dividends));
  }, [transactions, dividends]);

  const holdings = useMemo(() => {
    const map = new Map<string, Holding>();

    transactions.forEach(t => {
      const current = map.get(t.ticker) || { ticker: t.ticker, quantity: 0, averageCost: 0, totalInvested: 0 };
      if (t.type === TransactionType.BUY) {
        const newQuantity = current.quantity + t.quantity;
        const newInvestment = t.quantity * t.price + t.fees;
        current.totalInvested += newInvestment;
        current.quantity = newQuantity;
        current.averageCost = current.totalInvested / newQuantity;
      } else {
        const sellValue = t.quantity * t.price - t.fees;
        // In a real app, we'd calculate realized gain, but for inventory we just subtract qty
        current.quantity -= t.quantity;
        // Adjust total invested proportionally for simple inventory view
        if (current.quantity > 0) {
          current.totalInvested = current.quantity * current.averageCost;
        } else {
          current.totalInvested = 0;
          current.averageCost = 0;
        }
      }
      map.set(t.ticker, current);
    });

    return Array.from(map.values()).filter(h => h.quantity > 0);
  }, [transactions]);

  const addTransaction = (t: Transaction) => setTransactions([...transactions, t]);
  const addDividend = (d: Dividend) => setDividends([...dividends, d]);

  return (
    <div className="flex min-h-screen bg-slate-50">
      {/* Mobile Backdrop */}
      {isSidebarOpen && (
        <div 
          className="fixed inset-0 bg-black/50 z-40 lg:hidden"
          onClick={() => setIsSidebarOpen(false)}
        />
      )}

      {/* Sidebar */}
      <aside className={`
        fixed inset-y-0 left-0 z-50 w-64 bg-white border-r border-slate-200 transform transition-transform duration-200 ease-in-out lg:translate-x-0 lg:static
        ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'}
      `}>
        <div className="p-6">
          <div className="flex items-center space-x-3 mb-8">
            <div className="bg-blue-600 p-2 rounded-xl text-white">
              <TrendingUp size={24} />
            </div>
            <h1 className="text-xl font-bold text-slate-900 tracking-tight">WealthTrack Pro</h1>
          </div>

          <nav className="space-y-2">
            <SidebarItem to="/" icon={LayoutDashboard} label="Dashboard" active={location.pathname === '/'} />
            <SidebarItem to="/portfolio" icon={Wallet} label="Inventory" active={location.pathname === '/portfolio'} />
            <SidebarItem to="/transactions" icon={ArrowLeftRight} label="Transactions" active={location.pathname === '/transactions'} />
            <SidebarItem to="/dividends" icon={PiggyBank} label="Dividends" active={location.pathname === '/dividends'} />
            <SidebarItem to="/insights" icon={BrainCircuit} label="AI Insights" active={location.pathname === '/insights'} />
          </nav>
        </div>

        <div className="absolute bottom-0 left-0 w-full p-6">
          <div className="bg-slate-50 rounded-xl p-4 border border-slate-200">
            <p className="text-xs text-slate-500 mb-1">Total Invested</p>
            <p className="text-lg font-bold text-slate-900">
              ${holdings.reduce((acc, h) => acc + h.totalInvested, 0).toLocaleString(undefined, { minimumFractionDigits: 2 })}
            </p>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 overflow-x-hidden">
        {/* Header */}
        <header className="sticky top-0 z-30 bg-white/80 backdrop-blur-md border-b border-slate-200 px-6 py-4 flex items-center justify-between">
          <button 
            className="lg:hidden p-2 hover:bg-slate-100 rounded-lg text-slate-600"
            onClick={() => setIsSidebarOpen(true)}
          >
            <Menu size={24} />
          </button>
          <div className="flex-1 lg:flex-none">
            <h2 className="text-lg font-semibold text-slate-800">
              {location.pathname === '/' ? 'Portfolio Dashboard' : 
               location.pathname === '/portfolio' ? 'Current Holdings' :
               location.pathname === '/transactions' ? 'Transaction History' :
               location.pathname === '/dividends' ? 'Dividend Rewards' : 'AI Market Insights'}
            </h2>
          </div>
          <div className="flex items-center space-x-3">
             <Link 
                to="/transactions" 
                className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg text-sm font-medium flex items-center space-x-2 shadow-sm transition-all"
             >
               <PlusCircle size={18} />
               <span className="hidden sm:inline">Add Trade</span>
             </Link>
          </div>
        </header>

        <div className="p-4 md:p-8 max-w-7xl mx-auto">
          <Routes>
            <Route path="/" element={<Dashboard holdings={holdings} transactions={transactions} dividends={dividends} />} />
            <Route path="/portfolio" element={<Portfolio holdings={holdings} />} />
            <Route path="/transactions" element={<Transactions transactions={transactions} onAdd={addTransaction} />} />
            <Route path="/dividends" element={<Dividends dividends={dividends} onAdd={addDividend} />} />
            <Route path="/insights" element={<AIInsights holdings={holdings} transactions={transactions} />} />
          </Routes>
        </div>
      </main>
    </div>
  );
};

const App = () => {
  return (
    <HashRouter>
      <AppContent />
    </HashRouter>
  );
};

export default App;

import React, { useMemo } from 'react';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer, 
  PieChart, 
  Pie, 
  Cell,
  AreaChart,
  Area,
  Legend
} from 'recharts';
import { Transaction, Dividend, Holding } from '../types';
import { TrendingUp, DollarSign, Wallet, Activity } from 'lucide-react';

const COLORS = ['#2563eb', '#7c3aed', '#db2777', '#ea580c', '#16a34a', '#ca8a04', '#0891b2'];

interface DashboardProps {
  holdings: Holding[];
  transactions: Transaction[];
  dividends: Dividend[];
}

const StatCard = ({ title, value, icon: Icon, colorClass }: any) => (
  <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex items-center space-x-4">
    <div className={`p-3 rounded-xl ${colorClass}`}>
      <Icon size={24} />
    </div>
    <div>
      <p className="text-sm font-medium text-slate-500">{title}</p>
      <h3 className="text-2xl font-bold text-slate-900">{value}</h3>
    </div>
  </div>
);

const Dashboard: React.FC<DashboardProps> = ({ holdings, transactions, dividends }) => {
  const totalInvested = useMemo(() => holdings.reduce((acc, h) => acc + h.totalInvested, 0), [holdings]);
  const totalDividends = useMemo(() => dividends.reduce((acc, d) => acc + d.amount, 0), [dividends]);

  const allocationData = useMemo(() => {
    return holdings.map(h => ({
      name: h.ticker,
      value: h.totalInvested
    })).sort((a, b) => b.value - a.value);
  }, [holdings]);

  const dividendYearlyData = useMemo(() => {
    const years: Record<string, number> = {};
    dividends.forEach(d => {
      const year = new Date(d.date).getFullYear().toString();
      years[year] = (years[year] || 0) + d.amount;
    });
    return Object.keys(years).sort().map(year => ({
      year,
      amount: years[year]
    }));
  }, [dividends]);

  const investmentHistoryData = useMemo(() => {
    // Basic chronological aggregation of investment
    const sorted = [...transactions].sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());
    let runningTotal = 0;
    const history = sorted.map(t => {
      runningTotal += (t.type === 'BUY' ? (t.quantity * t.price + t.fees) : -(t.quantity * t.price - t.fees));
      return {
        date: t.date,
        total: runningTotal
      };
    });
    return history;
  }, [transactions]);

  return (
    <div className="space-y-8">
      {/* Summary Stats */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <StatCard 
          title="Total Principal" 
          value={`$${totalInvested.toLocaleString(undefined, { maximumFractionDigits: 0 })}`}
          icon={Wallet}
          colorClass="bg-blue-50 text-blue-600"
        />
        <StatCard 
          title="Total Dividends" 
          value={`$${totalDividends.toLocaleString(undefined, { minimumFractionDigits: 2 })}`}
          icon={DollarSign}
          colorClass="bg-emerald-50 text-emerald-600"
        />
        <StatCard 
          title="Active Holdings" 
          value={holdings.length}
          icon={Activity}
          colorClass="bg-purple-50 text-purple-600"
        />
        <StatCard 
          title="Avg. Yield" 
          value={`${totalInvested > 0 ? ((totalDividends / totalInvested) * 100).toFixed(2) : 0}%`}
          icon={TrendingUp}
          colorClass="bg-orange-50 text-orange-600"
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        {/* Allocation Chart */}
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
          <h3 className="text-lg font-bold text-slate-800 mb-6">Portfolio Allocation</h3>
          <div className="h-[300px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={allocationData}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={100}
                  paddingAngle={5}
                  dataKey="value"
                >
                  {allocationData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Pie>
                <Tooltip 
                   formatter={(value: number) => `$${value.toLocaleString()}`}
                   contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                />
                <Legend layout="vertical" align="right" verticalAlign="middle" />
              </PieChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Dividend Growth */}
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
          <h3 className="text-lg font-bold text-slate-800 mb-6">Yearly Dividend Income</h3>
          <div className="h-[300px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={dividendYearlyData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="year" axisLine={false} tickLine={false} tick={{ fill: '#64748b', fontSize: 12 }} />
                <YAxis axisLine={false} tickLine={false} tick={{ fill: '#64748b', fontSize: 12 }} tickFormatter={(val) => `$${val}`} />
                <Tooltip 
                   cursor={{ fill: '#f8fafc' }}
                   contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                   formatter={(val: number) => [`$${val.toFixed(2)}`, 'Dividend']}
                />
                <Bar dataKey="amount" fill="#10b981" radius={[4, 4, 0, 0]} barSize={40} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Investment History */}
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 lg:col-span-2">
          <h3 className="text-lg font-bold text-slate-800 mb-6">Total Invested Capital (Cumulative)</h3>
          <div className="h-[350px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <AreaChart data={investmentHistoryData}>
                <defs>
                  <linearGradient id="colorTotal" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#2563eb" stopOpacity={0.1}/>
                    <stop offset="95%" stopColor="#2563eb" stopOpacity={0}/>
                  </linearGradient>
                </defs>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="date" axisLine={false} tickLine={false} tick={{ fill: '#64748b', fontSize: 12 }} minTickGap={30} />
                <YAxis axisLine={false} tickLine={false} tick={{ fill: '#64748b', fontSize: 12 }} tickFormatter={(val) => `$${val.toLocaleString()}`} />
                <Tooltip 
                   contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                   formatter={(val: number) => [`$${val.toLocaleString()}`, 'Investment']}
                />
                <Area type="monotone" dataKey="total" stroke="#2563eb" strokeWidth={3} fillOpacity={1} fill="url(#colorTotal)" />
              </AreaChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React from 'react';
import { Holding } from '../types';

interface PortfolioProps {
  holdings: Holding[];
}

const Portfolio: React.FC<PortfolioProps> = ({ holdings }) => {
  return (
    <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
      <div className="overflow-x-auto">
        <table className="w-full text-left">
          <thead className="bg-slate-50 border-b border-slate-100">
            <tr>
              <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase tracking-wider">Ticker</th>
              <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase tracking-wider">Shares</th>
              <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase tracking-wider">Avg. Cost</th>
              <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase tracking-wider">Total Value</th>
              <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase tracking-wider text-right">Allocation</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {holdings.length === 0 ? (
              <tr>
                <td colSpan={5} className="px-6 py-12 text-center text-slate-400">
                  No holdings found. Start by adding a transaction.
                </td>
              </tr>
            ) : (
              holdings.map((h, i) => {
                const totalInvested = holdings.reduce((acc, curr) => acc + curr.totalInvested, 0);
                const allocation = (h.totalInvested / totalInvested) * 100;

                return (
                  <tr key={h.ticker} className="hover:bg-slate-50/50 transition-colors">
                    <td className="px-6 py-4">
                      <div className="flex items-center space-x-3">
                        <div className="w-8 h-8 rounded-lg bg-blue-100 flex items-center justify-center text-blue-700 font-bold text-xs">
                          {h.ticker[0]}
                        </div>
                        <span className="font-bold text-slate-900">{h.ticker}</span>
                      </div>
                    </td>
                    <td className="px-6 py-4 text-slate-600 font-medium">{h.quantity.toLocaleString()}</td>
                    <td className="px-6 py-4 text-slate-600">${h.averageCost.toFixed(2)}</td>
                    <td className="px-6 py-4">
                      <span className="font-bold text-slate-900">${h.totalInvested.toLocaleString()}</span>
                    </td>
                    <td className="px-6 py-4 text-right">
                      <div className="flex flex-col items-end">
                        <span className="text-sm text-slate-600 mb-1">{allocation.toFixed(1)}%</span>
                        <div className="w-24 h-1.5 bg-slate-100 rounded-full overflow-hidden">
                          <div 
                            className="h-full bg-blue-500 rounded-full" 
                            style={{ width: `${allocation}%` }}
                          />
                        </div>
                      </div>
                    </td>
                  </tr>
                );
              })
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default Portfolio;

import React, { useState } from 'react';
import { Dividend } from '../types';
import { Plus, PiggyBank, Calendar, Tag, DollarSign } from 'lucide-react';

interface DividendsProps {
  dividends: Dividend[];
  onAdd: (d: Dividend) => void;
}

const Dividends: React.FC<DividendsProps> = ({ dividends, onAdd }) => {
  const [showForm, setShowForm] = useState(false);
  const [formData, setFormData] = useState({
    date: new Date().toISOString().split('T')[0],
    ticker: '',
    amount: ''
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.ticker || !formData.amount) return;

    onAdd({
      id: Date.now().toString(),
      date: formData.date,
      ticker: formData.ticker.toUpperCase(),
      amount: parseFloat(formData.amount)
    });

    setFormData({
      date: new Date().toISOString().split('T')[0],
      ticker: '',
      amount: ''
    });
    setShowForm(false);
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div>
           <h3 className="text-xl font-bold text-slate-900">Dividend Tracker</h3>
           <p className="text-slate-500 text-sm">Monitor your passive income stream</p>
        </div>
        {!showForm && (
          <button 
            onClick={() => setShowForm(true)}
            className="flex items-center justify-center space-x-2 bg-emerald-600 text-white px-6 py-3 rounded-xl hover:bg-emerald-700 transition-colors"
          >
            <Plus size={20} />
            <span className="font-semibold">Record Dividend</span>
          </button>
        )}
      </div>

      {showForm && (
        <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-200">
          <div className="flex justify-between items-center mb-6">
            <h3 className="text-xl font-bold text-slate-900">New Dividend Payment</h3>
            <button 
              onClick={() => setShowForm(false)}
              className="text-slate-400 hover:text-slate-600"
            >
              Cancel
            </button>
          </div>
          <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div className="space-y-2">
              <label className="text-sm font-semibold text-slate-700">Date Received</label>
              <div className="relative">
                <Calendar className="absolute left-3 top-3 text-slate-400" size={18} />
                <input 
                  type="date" 
                  value={formData.date}
                  onChange={e => setFormData({...formData, date: e.target.value})}
                  className="w-full pl-10 pr-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-emerald-500 outline-none" 
                />
              </div>
            </div>
            <div className="space-y-2">
              <label className="text-sm font-semibold text-slate-700">Ticker Symbol</label>
              <div className="relative">
                <Tag className="absolute left-3 top-3 text-slate-400" size={18} />
                <input 
                  placeholder="e.g. KO"
                  value={formData.ticker}
                  onChange={e => setFormData({...formData, ticker: e.target.value})}
                  className="w-full pl-10 pr-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-emerald-500 outline-none" 
                />
              </div>
            </div>
            <div className="space-y-2">
              <label className="text-sm font-semibold text-slate-700">Amount Received</label>
              <div className="relative">
                <DollarSign className="absolute left-3 top-3 text-slate-400" size={18} />
                <input 
                  type="number" step="any"
                  value={formData.amount}
                  onChange={e => setFormData({...formData, amount: e.target.value})}
                  className="w-full pl-10 pr-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-emerald-500 outline-none" 
                />
              </div>
            </div>
            <div className="md:col-span-3">
              <button 
                type="submit"
                className="w-full bg-emerald-600 hover:bg-emerald-700 text-white font-bold py-3 rounded-xl transition-all shadow-lg shadow-emerald-100"
              >
                Save Dividend
              </button>
            </div>
          </form>
        </div>
