  BrainCircuit
} from 'lucide-react';
import Dashboard from './components/Dashboard';
import Transactions from './components/Transactions';
import Portfolio from './components/Portfolio';
import Dividends from './components/Dividends';
import AIInsights from './components/AIInsights';
import DataManagement from './components/DataManagement';
import { Transaction, Dividend, Holding, TransactionType } from './types';

// Initial Mock Data
const INITIAL_TRANSACTIONS: Transaction[] = [
  { id: '1', date: '2023-01-15', ticker: 'AAPL', name: 'Apple Inc.', type: TransactionType.BUY, quantity: 10, price: 145.00, fees: 5 },
  { id: '2', date: '2023-03-10', ticker: 'MSFT', name: 'Microsoft Corporation', type: TransactionType.BUY, quantity: 5, price: 250.00, fees: 5 },
