const INITIAL_TRANSACTIONS: Transaction[] = [
  { id: '1', date: '2023-01-15', ticker: 'AAPL', name: 'Apple Inc.', type: TransactionType.BUY, quantity: 10, price: 145.00, fees: 5 },
