  { id: 'd1', date: '2023-02-15', ticker: 'AAPL', name: 'Apple Inc.', amount: 2.30 },
  { id: 'd2', date: '2023-05-15', ticker: 'AAPL', name: 'Apple Inc.', amount: 2.40 },
