import React, { useRef, useState } from 'react';
import { Download, Upload, FileText, CheckCircle2, AlertCircle, PiggyBank, Trash2 } from 'lucide-react';
import { Transaction, Dividend, TransactionType } from '../types';

interface DataManagementProps {
  transactions: Transaction[];
  dividends: Dividend[];
  onImportTransactions: (ts: Transaction[]) => void;
  onImportDividends: (ds: Dividend[]) => void;
}

const DataManagement: React.FC<DataManagementProps> = ({ 
  transactions, 
  dividends, 
  onImportTransactions, 
  onImportDividends 
}) => {
  const [message, setMessage] = useState<{ text: string; type: 'success' | 'error' } | null>(null);
  const transactionInputRef = useRef<HTMLInputElement>(null);
  const dividendInputRef = useRef<HTMLInputElement>(null);

  const showMessage = (text: string, type: 'success' | 'error') => {
    setMessage({ text, type });
    setTimeout(() => setMessage(null), 3000);
  };

  const handleClearTransactions = () => {
    if (window.confirm('Are you sure you want to clear ALL transaction history? This cannot be undone.')) {
      onImportTransactions([]);
      showMessage('All transactions cleared.', 'success');
    }
  };

  const handleClearDividends = () => {
    if (window.confirm('Are you sure you want to clear ALL dividend records? This cannot be undone.')) {
      onImportDividends([]);
      showMessage('All dividend records cleared.', 'success');
    }
  };

  const downloadCSV = (content: string, fileName: string) => {
    const blob = new Blob([content], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    const url = URL.createObjectURL(blob);
    link.setAttribute('href', url);
    link.setAttribute('download', fileName);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const exportTransactions = () => {
    const headers = ['id', 'date', 'ticker', 'name', 'type', 'quantity', 'price', 'fees'];
    const rows = transactions.map(t => [
      t.id, t.date, t.ticker, t.name, t.type, t.quantity, t.price, t.fees
    ]);
    const csvContent = [headers, ...rows].map(e => e.join(',')).join('\n');
    downloadCSV(csvContent, `transactions_${new Date().toISOString().split('T')[0]}.csv`);
    showMessage('Transactions exported successfully!', 'success');
  };

  const exportDividends = () => {
    const headers = ['id', 'date', 'ticker', 'name', 'amount'];
    const rows = dividends.map(d => [
      d.id, d.date, d.ticker, d.name, d.amount
    ]);
    const csvContent = [headers, ...rows].map(e => e.join(',')).join('\n');
    downloadCSV(csvContent, `dividends_${new Date().toISOString().split('T')[0]}.csv`);
    showMessage('Dividends exported successfully!', 'success');
  };

  const handleImportTransactions = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const text = event.target?.result as string;
        const lines = text.split('\n').filter(l => l.trim());
        const imported: Transaction[] = lines.slice(1).map(line => {
          const parts = line.split(',');
          return {
            id: parts[0] || Date.now().toString() + Math.random(),
            date: parts[1],
            ticker: parts[2],
            name: parts[3],
            type: parts[4] as TransactionType,
            quantity: parseFloat(parts[5]),
            price: parseFloat(parts[6]),
            fees: parseFloat(parts[7] || '0')
          };
        });
        onImportTransactions([...transactions, ...imported]);
        showMessage(`Imported ${imported.length} transactions!`, 'success');
      } catch (err) {
        showMessage('Failed to parse Transactions CSV.', 'error');
      }
    };
    reader.readAsText(file);
    e.target.value = '';
  };

  const handleImportDividends = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const text = event.target?.result as string;
        const lines = text.split('\n').filter(l => l.trim());
        const imported: Dividend[] = lines.slice(1).map(line => {
          const parts = line.split(',');
          return {
            id: parts[0] || Date.now().toString() + Math.random(),
            date: parts[1],
            ticker: parts[2],
            name: parts[3],
            amount: parseFloat(parts[4])
          };
        });
        onImportDividends([...dividends, ...imported]);
        showMessage(`Imported ${imported.length} dividends!`, 'success');
      } catch (err) {
        showMessage('Failed to parse Dividends CSV.', 'error');
      }
    };
    reader.readAsText(file);
    e.target.value = '';
  };

  return (
    <div className="space-y-6">
      {message && (
        <div className={`fixed top-20 right-8 z-50 flex items-center space-x-2 px-6 py-4 rounded-2xl shadow-lg border animate-in slide-in-from-right-8 duration-300 ${
          message.type === 'success' ? 'bg-emerald-50 border-emerald-100 text-emerald-700' : 'bg-red-50 border-red-100 text-red-700'
        }`}>
          {message.type === 'success' ? <CheckCircle2 size={20} /> : <AlertCircle size={20} />}
          <span className="font-semibold">{message.text}</span>
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        {/* Transactions Card */}
        <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100">
          <div className="flex items-center space-x-3 mb-6">
            <div className="p-3 bg-blue-50 text-blue-600 rounded-2xl">
              <FileText size={24} />
            </div>
            <div>
              <h3 className="text-xl font-bold text-slate-900">Transactions Data</h3>
              <p className="text-sm text-slate-500">{transactions.length} records found</p>
