import React, { useMemo } from 'react';
import { 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer, 
  PieChart, 
  Pie, 
  Cell,
  Bar,
  Line,
  ComposedChart,
  Legend,
  ReferenceLine
} from 'recharts';
import { Transaction, Dividend, Holding, TransactionType } from '../types';
import { TrendingUp, DollarSign, Wallet, Activity } from 'lucide-react';

const COLORS = ['#2563eb', '#7c3aed', '#db2777', '#ea580c', '#16a34a', '#ca8a04', '#0891b2'];

interface DashboardProps {
  holdings: Holding[];
  transactions: Transaction[];
  dividends: Dividend[];
}

const StatCard = ({ title, value, icon: Icon, colorClass }: any) => (
  <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex items-center space-x-4">
    <div className={`p-3 rounded-xl ${colorClass}`}>
      <Icon size={24} />
    </div>
    <div>
      <p className="text-sm font-medium text-slate-500">{title}</p>
      <h3 className="text-2xl font-bold text-slate-900">{value}</h3>
    </div>
  </div>
);

const Dashboard: React.FC<DashboardProps> = ({ holdings, transactions, dividends }) => {
  const totalInvested = useMemo(() => holdings.reduce((acc, h) => acc + h.totalInvested, 0), [holdings]);
  const totalDividends = useMemo(() => dividends.reduce((acc, d) => acc + d.amount, 0), [dividends]);

  const yearlyPerformanceData = useMemo(() => {
    const years: Record<string, { dividend: number; capitalGain: number }> = {};

    // 1. Initialize years from all transactions to ensure gaps are handled
    transactions.forEach(t => {
      const year = new Date(t.date).getFullYear().toString();
      if (!years[year]) years[year] = { dividend: 0, capitalGain: 0 };
    });

    // 2. Process Dividends
    dividends.forEach(d => {
      const year = new Date(d.date).getFullYear().toString();
      if (!years[year]) years[year] = { dividend: 0, capitalGain: 0 };
      years[year].dividend += d.amount;
    });

    // 3. Process Realized Capital Gains
    const costBasisMap: Record<string, { qty: number; totalCost: number }> = {};
    const sortedTx = [...transactions].sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());

    sortedTx.forEach(t => {
      const year = new Date(t.date).getFullYear().toString();

      if (t.type === TransactionType.BUY) {
        if (!costBasisMap[t.ticker]) costBasisMap[t.ticker] = { qty: 0, totalCost: 0 };
        costBasisMap[t.ticker].qty += t.quantity;
        costBasisMap[t.ticker].totalCost += (t.quantity * t.price + t.fees);
      } else if (t.type === TransactionType.SELL) {
        if (costBasisMap[t.ticker] && costBasisMap[t.ticker].qty > 0) {
          const avgPrice = costBasisMap[t.ticker].totalCost / costBasisMap[t.ticker].qty;
          const gain = (t.price * t.quantity - t.fees) - (avgPrice * t.quantity);
          years[year].capitalGain += gain;

          // Update cost basis (Inventory decreases)
          costBasisMap[t.ticker].qty -= t.quantity;
          costBasisMap[t.ticker].totalCost = costBasisMap[t.ticker].qty * avgPrice;
        }
      }
    });

    // 4. Transform to array and calculate cumulative
    let runningTotalProfit = 0;
    return Object.keys(years).sort().map(year => {
      const yearlyProfit = years[year].dividend + years[year].capitalGain;
      runningTotalProfit += yearlyProfit;

      return {
        year,
        dividend: Number(years[year].dividend.toFixed(2)),
        capitalGain: Number(years[year].capitalGain.toFixed(2)),
        cumulativeProfit: Number(runningTotalProfit.toFixed(2))
      };
    });
  }, [dividends, transactions]);

  const allocationData = useMemo(() => {
    return holdings.map(h => ({
      name: h.ticker,
      value: h.totalInvested
    })).sort((a, b) => b.value - a.value);
  }, [holdings]);

  const totalRealizedGain = useMemo(() => 
    yearlyPerformanceData.reduce((acc, curr) => acc + curr.capitalGain, 0)
  , [yearlyPerformanceData]);

  return (
    <div className="space-y-8">
      {/* Summary Stats */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <StatCard 
          title="Total Principal" 
          value={`$${totalInvested.toLocaleString(undefined, { maximumFractionDigits: 0 })}`}
          icon={Wallet}
          colorClass="bg-blue-50 text-blue-600"
        />
        <StatCard 
          title="Total Dividends" 
          value={`$${totalDividends.toLocaleString(undefined, { minimumFractionDigits: 2 })}`}
          icon={DollarSign}
          colorClass="bg-emerald-50 text-emerald-600"
        />
        <StatCard 
          title="Realized Gains" 
          value={`$${totalRealizedGain.toLocaleString(undefined, { minimumFractionDigits: 2 })}`}
          icon={TrendingUp}
          colorClass={`${totalRealizedGain >= 0 ? 'bg-indigo-50 text-indigo-600' : 'bg-red-50 text-red-600'}`}
        />
        <StatCard 
          title="Active Holdings" 
          value={holdings.length}
          icon={Activity}
          colorClass="bg-purple-50 text-purple-600"
        />
      </div>

      {/* Improved Annual Performance Chart */}
      <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100">
        <div className="flex items-center justify-between mb-8">
          <div>
            <h3 className="text-xl font-bold text-slate-800">Annual Performance Portfolio</h3>
            <p className="text-sm text-slate-500">Year-by-year realized gains vs dividend income</p>
          </div>
          <div className="bg-slate-50 p-2 rounded-xl">
             <TrendingUp className="text-slate-400" size={24} />
          </div>
        </div>
        <div className="h-[400px] w-full">
          {yearlyPerformanceData.length > 0 ? (
            <ResponsiveContainer width="100%" height="100%">
              <ComposedChart data={yearlyPerformanceData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis 
                  dataKey="year" 
                  axisLine={false} 
                  tickLine={false} 
                  tick={{ fill: '#64748b', fontSize: 13, fontWeight: 500 }} 
                />
                <YAxis 
                  axisLine={false} 
                  tickLine={false} 
                  tick={{ fill: '#64748b', fontSize: 12 }} 
                  tickFormatter={(val) => `$${val}`}
                />
                <Tooltip 
                  contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)', padding: '12px' }}
                  formatter={(val: number) => [`$${val.toLocaleString()}`, '']}
                />
                <Legend verticalAlign="top" height={40} iconType="circle" />
                <ReferenceLine y={0} stroke="#cbd5e1" strokeWidth={1} />

                {/* Realized Gains Bar */}
                <Bar 
                  name="Annual Realized Gain/Loss" 
                  dataKey="capitalGain" 
                  fill="#3b82f6" 
                  radius={[4, 4, 0, 0]} 
                  barSize={30}
                />

                {/* Dividend Bar */}
                <Bar 
                  name="Annual Dividend Income" 
                  dataKey="dividend" 
                  fill="#10b981" 
                  radius={[4, 4, 0, 0]} 
                  barSize={30}
                />

                {/* Cumulative Profit Line */}
                <Line
                  name="Cumulative Total Profit"
                  type="monotone"
                  dataKey="cumulativeProfit"
                  stroke="#7c3aed"
                  strokeWidth={3}
                  dot={{ r: 4, fill: '#7c3aed', strokeWidth: 2, stroke: '#fff' }}
                />
              </ComposedChart>
            </ResponsiveContainer>
          ) : (
            <div className="flex flex-col items-center justify-center h-full text-slate-400">
               <Activity size={48} className="mb-4 opacity-20" />
               <p>No transaction history available to plot trends.</p>
            </div>
          )}
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        {/* Allocation Chart */}
        <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100">
          <h3 className="text-lg font-bold text-slate-800 mb-6">Asset Allocation</h3>
          <div className="h-[300px] w-full">
            {allocationData.length > 0 ? (
              <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie
                    data={allocationData}
                    cx="50%"
                    cy="50%"
                    innerRadius={70}
                    outerRadius={100}
                    paddingAngle={8}
                    dataKey="value"
                  >
                    {allocationData.map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                    ))}
                  </Pie>
                  <Tooltip 
                     formatter={(value: number) => `$${value.toLocaleString()}`}
                     contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                  />
                  <Legend layout="vertical" align="right" verticalAlign="middle" />
                </PieChart>
              </ResponsiveContainer>
            ) : (
              <div className="flex items-center justify-center h-full text-slate-400 italic">
                Add transactions to see allocation
              </div>
            )}
          </div>
        </div>

        {/* Efficiency Tips */}
        <div className="bg-slate-900 p-8 rounded-3xl text-white flex flex-col justify-center">
          <div className="flex items-center space-x-3 mb-4 text-blue-400">
            <TrendingUp size={24} />
            <h3 className="text-lg font-bold">Strategy Insights</h3>
          </div>
          <p className="text-slate-400 leading-relaxed mb-6 text-sm">
            This dashboard tracks your **Realized Performance**. Capital gains only appear when you sell a stock at a profit. Dividends contribute to your **Cumulative Profit** (purple line), which shows the steady growth of your investment engine over the years.
          </p>
          <div className="grid grid-cols-2 gap-4">
            <div className="bg-white/5 p-4 rounded-2xl border border-white/10">
              <p className="text-[10px] text-slate-500 uppercase font-bold tracking-wider mb-1">Total Dividends</p>
              <p className="text-xl font-bold text-emerald-400">
                ${totalDividends.toLocaleString(undefined, { maximumFractionDigits: 0 })}
              </p>
            </div>
            <div className="bg-white/5 p-4 rounded-2xl border border-white/10">
              <p className="text-[10px] text-slate-500 uppercase font-bold tracking-wider mb-1">Total Realized Gain</p>
              <p className="text-xl font-bold text-blue-400">
                ${totalRealizedGain.toLocaleString(undefined, { maximumFractionDigits: 0 })}
