import React, { useState, useEffect, useMemo } from 'react';
import { HashRouter, Routes, Route, Link, useLocation } from 'react-router-dom';
import { 
  LayoutDashboard, 
  ArrowLeftRight, 
  Wallet, 
  PiggyBank, 
  PlusCircle, 
  Menu, 
  TrendingUp,
  Database
} from 'lucide-react';
import Dashboard from './components/Dashboard';
import Transactions from './components/Transactions';
import Portfolio from './components/Portfolio';
import Dividends from './components/Dividends';
import DataManagement from './components/DataManagement';
import { Transaction, Dividend, Holding, TransactionType } from './types';

const INITIAL_TRANSACTIONS: Transaction[] = [];
const INITIAL_DIVIDENDS: Dividend[] = [];

const SidebarItem = ({ to, icon: Icon, label, active }: { to: string, icon: any, label: string, active: boolean }) => (
  <Link
    to={to}
    className={`flex items-center space-x-3 px-4 py-3 rounded-lg transition-colors ${
      active 
        ? 'bg-blue-600 text-white shadow-lg shadow-blue-200' 
        : 'text-slate-600 hover:bg-slate-100'
    }`}
  >
    <Icon size={20} />
    <span className="font-medium">{label}</span>
  </Link>
);

const AppContent = () => {
  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    try {
      const saved = localStorage.getItem('wt_transactions');
      return saved ? JSON.parse(saved) : INITIAL_TRANSACTIONS;
    } catch {
      return INITIAL_TRANSACTIONS;
    }
  });

  const [dividends, setDividends] = useState<Dividend[]>(() => {
    try {
      const saved = localStorage.getItem('wt_dividends');
      return saved ? JSON.parse(saved) : INITIAL_DIVIDENDS;
    } catch {
      return INITIAL_DIVIDENDS;
    }
  });

  const [dividendEstimates, setDividendEstimates] = useState<Record<string, number>>(() => {
    try {
      const saved = localStorage.getItem('wt_div_estimates');
      return saved ? JSON.parse(saved) : {};
    } catch {
      return {};
    }
  });

  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const location = useLocation();

  useEffect(() => {
    localStorage.setItem('wt_transactions', JSON.stringify(transactions));
    localStorage.setItem('wt_dividends', JSON.stringify(dividends));
    localStorage.setItem('wt_div_estimates', JSON.stringify(dividendEstimates));
  }, [transactions, dividends, dividendEstimates]);

  const updateDividendEstimate = (ticker: string, value: number) => {
    setDividendEstimates(prev => ({
      ...prev,
      [ticker]: value
    }));
  };

  const holdings = useMemo(() => {
    const map = new Map<string, Holding>();
    // Sort transactions by date and type (BUY first)
    const sortedTransactions = [...transactions].sort((a, b) => {
      if (a.date !== b.date) return a.date.localeCompare(b.date);
      return a.type === TransactionType.BUY ? -1 : 1;
    });

    sortedTransactions.forEach(t => {
      const current: Holding = map.get(t.ticker) || { 
        ticker: t.ticker, 
        name: t.name, 
        quantity: 0, 
        averageCost: 0, 
        totalInvested: 0,
        estimatedDividendPerShare: dividendEstimates[t.ticker] || 0,
        estimatedTotalDividend: 0
      };

      if (t.type === TransactionType.BUY) {
        const newQuantity = current.quantity + t.quantity;
        const newInvestment = t.quantity * t.price + t.fees;
        current.totalInvested += newInvestment;
        current.quantity = newQuantity;
        current.averageCost = current.totalInvested / newQuantity;
      } else {
        const soldQty = Math.min(t.quantity, current.quantity);
        current.quantity -= soldQty;
        if (current.quantity > 0) {
          current.totalInvested = current.quantity * current.averageCost;
        } else {
          current.totalInvested = 0;
          current.averageCost = 0;
        }
      }

      current.estimatedDividendPerShare = dividendEstimates[t.ticker] || 0;
      current.estimatedTotalDividend = current.quantity * (current.estimatedDividendPerShare || 0);

      map.set(t.ticker, current);
    });

    return Array.from(map.values()).filter(h => h.quantity > 0);
  }, [transactions, dividendEstimates]);

  const addTransaction = (t: Transaction) => setTransactions(prev => [...prev, t]);
  const removeTransaction = (id: string) => setTransactions(prev => prev.filter(t => t.id !== id));

  const addDividend = (d: Dividend) => setDividends(prev => [...prev, d]);
  const removeDividend = (id: string) => setDividends(prev => prev.filter(d => d.id !== id));

  const resetAllData = () => {
    setTransactions([]);
    setDividends([]);
    setDividendEstimates({});
    localStorage.clear();
  };

  return (
    <div className="flex min-h-screen bg-slate-50">
      {isSidebarOpen && (
        <div 
          className="fixed inset-0 bg-black/50 z-40 lg:hidden"
          onClick={() => setIsSidebarOpen(false)}
        />
      )}

      <aside className={`
        fixed inset-y-0 left-0 z-50 w-64 bg-white border-r border-slate-200 transform transition-transform duration-200 ease-in-out lg:translate-x-0 lg:static
        ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'}
      `}>
        <div className="p-6">
          <div className="flex items-center space-x-3 mb-8">
            <div className="bg-blue-600 p-2 rounded-xl text-white">
              <TrendingUp size={24} />
            </div>
            <h1 className="text-xl font-bold text-slate-900 tracking-tight">WealthTrack Pro</h1>
          </div>

          <nav className="space-y-2">
            <SidebarItem to="/" icon={LayoutDashboard} label="Dashboard" active={location.pathname === '/'} />
            <SidebarItem to="/portfolio" icon={Wallet} label="Inventory" active={location.pathname === '/portfolio'} />
            <SidebarItem to="/transactions" icon={ArrowLeftRight} label="Transactions" active={location.pathname === '/transactions'} />
            <SidebarItem to="/dividends" icon={PiggyBank} label="Dividends" active={location.pathname === '/dividends'} />
            <SidebarItem to="/data" icon={Database} label="Data Manager" active={location.pathname === '/data'} />
          </nav>
        </div>

        <div className="absolute bottom-0 left-0 w-full p-6">
          <div className="bg-slate-50 rounded-xl p-4 border border-slate-200">
            <p className="text-xs text-slate-500 mb-1">Total Cost (Inventory)</p>
            <p className="text-lg font-bold text-slate-900">
              ${holdings.reduce((acc, h) => acc + h.totalInvested, 0).toLocaleString(undefined, { minimumFractionDigits: 2 })}
            </p>
          </div>
        </div>
      </aside>

      <main className="flex-1 overflow-x-hidden">
        <header className="sticky top-0 z-30 bg-white/80 backdrop-blur-md border-b border-slate-200 px-6 py-4 flex items-center justify-between">
          <button 
            className="lg:hidden p-2 hover:bg-slate-100 rounded-lg text-slate-600"
            onClick={() => setIsSidebarOpen(true)}
          >
            <Menu size={24} />
          </button>
          <div className="flex-1 lg:flex-none">
            <h2 className="text-lg font-semibold text-slate-800">
              {location.pathname === '/' ? 'Portfolio Dashboard' : 
               location.pathname === '/portfolio' ? 'Current Holdings' :
               location.pathname === '/transactions' ? 'Transaction History' :
               location.pathname === '/dividends' ? 'Dividend Rewards' : 'Data Management'}
            </h2>
          </div>
          <div className="flex items-center space-x-3">
             <Link 
                to="/transactions" 
                className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg text-sm font-medium flex items-center space-x-2 shadow-sm transition-all"
             >
               <PlusCircle size={18} />
               <span className="hidden sm:inline">Add Trade</span>
             </Link>
          </div>
        </header>

        <div className="p-4 md:p-8 max-w-7xl mx-auto">
          <Routes>
            <Route path="/" element={<Dashboard holdings={holdings} transactions={transactions} dividends={dividends} />} />
            <Route 
              path="/portfolio" 
              element={<Portfolio holdings={holdings} onUpdateEstimate={updateDividendEstimate} />} 
            />
            <Route path="/transactions" element={<Transactions transactions={transactions} onAdd={addTransaction} onDelete={removeTransaction} />} />
            <Route path="/dividends" element={<Dividends dividends={dividends} onAdd={addDividend} onDelete={removeDividend} />} />
            <Route 
              path="/data" 
              element={
                <DataManagement 
                  transactions={transactions} 
                  dividends={dividends} 
                  onImportTransactions={setTransactions} 
                  onImportDividends={setDividends}
                  onResetAll={resetAllData}
                />
              } 
            />
          </Routes>
        </div>
      </main>
    </div>
  );
};

const App = () => {
  return (
    <HashRouter>
      <AppContent />
    </HashRouter>
  );
};

export default App;

import React, { useMemo } from 'react';
import { 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer, 
  PieChart, 
  Pie, 
  Cell,
  Bar,
  Line,
  ComposedChart,
  Legend,
  ReferenceLine
} from 'recharts';
import { Transaction, Dividend, Holding, TransactionType } from '../types';
import { TrendingUp, DollarSign, Wallet, Activity } from 'lucide-react';

const COLORS = ['#2563eb', '#7c3aed', '#db2777', '#ea580c', '#16a34a', '#ca8a04', '#0891b2'];

interface DashboardProps {
  holdings: Holding[];
  transactions: Transaction[];
  dividends: Dividend[];
}

const StatCard = ({ title, value, icon: Icon, colorClass }: any) => (
  <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex items-center space-x-4">
    <div className={`p-3 rounded-xl ${colorClass}`}>
      <Icon size={24} />
    </div>
    <div>
      <p className="text-sm font-medium text-slate-500">{title}</p>
      <h3 className="text-2xl font-bold text-slate-900">{value}</h3>
    </div>
  </div>
);

const Dashboard: React.FC<DashboardProps> = ({ holdings, transactions, dividends }) => {
  const totalInvestedAtCost = useMemo(() => holdings.reduce((acc, h) => acc + h.totalInvested, 0), [holdings]);
  const totalDividends = useMemo(() => dividends.reduce((acc, d) => acc + d.amount, 0), [dividends]);

  const { yearlyData, grandTotalRealizedGain } = useMemo(() => {
    const years: Record<string, { dividend: number; capitalGain: number }> = {};
    let runningTotalRealizedGain = 0;

    // 1. Initialize all unique years from transactions and dividends
    transactions.forEach(t => {
      const year = t.date.split('-')[0];
      if (!years[year]) years[year] = { dividend: 0, capitalGain: 0 };
    });
    dividends.forEach(d => {
      const year = d.date.split('-')[0];
      if (!years[year]) years[year] = { dividend: 0, capitalGain: 0 };
    });

    // 2. Sort Transactions precisely: Date first, then BUY before SELL within same date
    const sortedTx = [...transactions].sort((a, b) => {
      if (a.date !== b.date) return a.date.localeCompare(b.date);
      // Ensure BUY is processed before SELL on the same day to maintain correct cost basis
      return a.type === TransactionType.BUY ? -1 : 1;
    });

    // 3. Process Realized Capital Gains with Cost Basis Tracking (FIFO-like weighted average)
    const costBasisMap: Record<string, { qty: number; totalCost: number }> = {};

    sortedTx.forEach(t => {
      const year = t.date.split('-')[0];

      if (t.type === TransactionType.BUY) {
        if (!costBasisMap[t.ticker]) costBasisMap[t.ticker] = { qty: 0, totalCost: 0 };
        costBasisMap[t.ticker].qty += t.quantity;
        costBasisMap[t.ticker].totalCost += (t.quantity * t.price + t.fees);
      } else if (t.type === TransactionType.SELL) {
        if (costBasisMap[t.ticker] && costBasisMap[t.ticker].qty > 0) {
          const avgPurchasePrice = costBasisMap[t.ticker].totalCost / costBasisMap[t.ticker].qty;

          // Formula: (Sold Qty * Sold Price - Sell Fees) - (Sold Qty * Avg Purchase Price)
          const netProceeds = (t.price * t.quantity) - t.fees;
          const costOfSharesSold = avgPurchasePrice * t.quantity;
          const gain = netProceeds - costOfSharesSold;

          years[year].capitalGain += gain;
          runningTotalRealizedGain += gain;

          // Update remaining inventory cost basis
          costBasisMap[t.ticker].qty -= t.quantity;
          // If qty reaches zero, ensure cost is also reset to prevent floating point residue
          if (costBasisMap[t.ticker].qty <= 0) {
            costBasisMap[t.ticker].totalCost = 0;
            costBasisMap[t.ticker].qty = 0;
          } else {
            costBasisMap[t.ticker].totalCost = costBasisMap[t.ticker].qty * avgPurchasePrice;
          }
        }
      }
    });

    // 4. Sum Dividends by Year
    dividends.forEach(d => {
      const year = d.date.split('-')[0];
      if (years[year]) {
        years[year].dividend += d.amount;
      }
    });

    // 5. Transform to array and calculate cumulative series
    let runningTotalProfit = 0;
    const yearlyDataArray = Object.keys(years).sort().map(year => {
      const yearlyProfit = years[year].dividend + years[year].capitalGain;
      runningTotalProfit += yearlyProfit;

      return {
        year,
        dividend: years[year].dividend,
        capitalGain: years[year].capitalGain,
        cumulativeProfit: runningTotalProfit
      };
    });

    return { 
      yearlyData: yearlyDataArray, 
      grandTotalRealizedGain: runningTotalRealizedGain 
    };
  }, [dividends, transactions]);

  const allocationData = useMemo(() => {
    return holdings.map(h => ({
      name: h.ticker,
      value: h.totalInvested
    })).sort((a, b) => b.value - a.value);
  }, [holdings]);

  return (
    <div className="space-y-8">
      {/* Summary Stats */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <StatCard 
          title="Current Cost Basis" 
          value={`$${totalInvestedAtCost.toLocaleString(undefined, { maximumFractionDigits: 0 })}`}
          icon={Wallet}
          colorClass="bg-blue-50 text-blue-600"
        />
        <StatCard 
          title="Total Passive Income" 
          value={`$${totalDividends.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`}
          icon={DollarSign}
          colorClass="bg-emerald-50 text-emerald-600"
        />
        <StatCard 
          title="Realized Performance" 
          value={`$${grandTotalRealizedGain.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`}
          icon={TrendingUp}
          colorClass={`${grandTotalRealizedGain >= 0 ? 'bg-indigo-50 text-indigo-600' : 'bg-red-50 text-red-600'}`}
        />
        <StatCard 
          title="Total Holdings" 
          value={holdings.length}
          icon={Activity}
          colorClass="bg-purple-50 text-purple-600"
        />
      </div>

      {/* Performance Graph */}
      <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100">
        <div className="flex items-center justify-between mb-8">
          <div>
            <h3 className="text-xl font-bold text-slate-800">Growth & Gains Evolution</h3>
            <p className="text-sm text-slate-500">Visualization of annual returns and cumulative success</p>
          </div>
          <div className="bg-slate-50 p-2 rounded-xl text-indigo-600">
             <TrendingUp size={24} />
          </div>
        </div>
        <div className="h-[400px] w-full">
          {yearlyData.length > 0 ? (
            <ResponsiveContainer width="100%" height="100%">
              <ComposedChart data={yearlyData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis 
                  dataKey="year" 
                  axisLine={false} 
                  tickLine={false} 
                  tick={{ fill: '#64748b', fontSize: 13, fontWeight: 500 }} 
                />
                <YAxis 
                  axisLine={false} 
                  tickLine={false} 
                  tick={{ fill: '#64748b', fontSize: 12 }} 
                  tickFormatter={(val) => `$${(val/1000).toFixed(0)}k`}
                />
                <Tooltip 
                  contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)', padding: '12px' }}
                  formatter={(val: number) => [`$${val.toLocaleString(undefined, { minimumFractionDigits: 2 })}`, '']}
                />
                <Legend verticalAlign="top" height={40} iconType="circle" />
                <ReferenceLine y={0} stroke="#cbd5e1" strokeWidth={1} />

                <Bar 
                  name="Annual Realized Gain" 
                  dataKey="capitalGain" 
                  fill="#3b82f6" 
                  radius={[4, 4, 0, 0]} 
                  barSize={30}
                />

                <Bar 
                  name="Annual Dividends" 
                  dataKey="dividend" 
                  fill="#10b981" 
                  radius={[4, 4, 0, 0]} 
                  barSize={30}
                />

                <Line
                  name="Cumulative Wealth Created"
                  type="monotone"
                  dataKey="cumulativeProfit"
                  stroke="#7c3aed"
                  strokeWidth={3}
                  dot={{ r: 4, fill: '#7c3aed', strokeWidth: 2, stroke: '#fff' }}
                />
              </ComposedChart>
            </ResponsiveContainer>
          ) : (
            <div className="flex flex-col items-center justify-center h-full text-slate-400">
               <Activity size={48} className="mb-4 opacity-20" />
               <p>Provide transaction data to generate your performance map.</p>
            </div>
          )}
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100">
          <h3 className="text-lg font-bold text-slate-800 mb-6">Asset Distribution</h3>
          <div className="h-[300px] w-full">
            {allocationData.length > 0 ? (
              <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie
                    data={allocationData}
                    cx="50%"
                    cy="50%"
                    innerRadius={70}
                    outerRadius={100}
                    paddingAngle={8}
                    dataKey="value"
                  >
                    {allocationData.map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                    ))}
                  </Pie>
                  <Tooltip 
                     formatter={(value: number) => `$${value.toLocaleString()}`}
                     contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                  />
                  <Legend layout="vertical" align="right" verticalAlign="middle" />
                </PieChart>
              </ResponsiveContainer>
            ) : (
              <div className="flex items-center justify-center h-full text-slate-400 italic">
                Inventory data is required for allocation view.
              </div>
            )}
          </div>
        </div>

        <div className="bg-slate-900 p-8 rounded-3xl text-white flex flex-col justify-center">
          <div className="flex items-center space-x-3 mb-4 text-blue-400">
            <TrendingUp size={24} />
            <h3 className="text-lg font-bold">Calculation Insights</h3>
          </div>
          <p className="text-slate-400 leading-relaxed mb-6 text-sm">
            WealthTrack Pro utilizes a **Weighted Average Cost Basis** for precision. Every SELL transaction is calculated against your specific historical buy-ins. Your cumulative profit (purple line) represents your total investment power growth, encompassing both capital gains and passive dividend yields.
          </p>
          <div className="grid grid-cols-2 gap-4">
            <div className="bg-white/5 p-4 rounded-2xl border border-white/10">
              <p className="text-[10px] text-slate-500 uppercase font-bold tracking-wider mb-1">Total Dividends</p>
              <p className="text-xl font-bold text-emerald-400">
                ${totalDividends.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
              </p>
            </div>
            <div className="bg-white/5 p-4 rounded-2xl border border-white/10">
              <p className="text-[10px] text-slate-500 uppercase font-bold tracking-wider mb-1">Realized Gains</p>
              <p className="text-xl font-bold text-blue-400">
                ${grandTotalRealizedGain.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
              </p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

