import React, { useState, useEffect, useRef } from 'react';
import { GoogleGenAI, Type } from "@google/genai";
import { Search, Loader2, Tag, Check, CircleSlash } from 'lucide-react';

export interface Suggestion {
  ticker: string;
  name: string;
  exchange: string;
}

// Local database of popular stocks to ensure functionality without API
const LOCAL_STOCKS: Suggestion[] = [
  { ticker: '2330.TW', name: '台積電 (TSMC)', exchange: 'TWSE' },
  { ticker: '0050.TW', name: '元大台灣50', exchange: 'TWSE' },
  { ticker: '2317.TW', name: '鴻海 (Foxconn)', exchange: 'TWSE' },
  { ticker: 'AAPL', name: 'Apple Inc.', exchange: 'NASDAQ' },
  { ticker: 'TSLA', name: 'Tesla, Inc.', exchange: 'NASDAQ' },
  { ticker: 'NVDA', name: 'NVIDIA Corporation', exchange: 'NASDAQ' },
  { ticker: 'MSFT', name: 'Microsoft Corporation', exchange: 'NASDAQ' },
  { ticker: 'GOOGL', name: 'Alphabet Inc.', exchange: 'NASDAQ' },
  { ticker: 'AMZN', name: 'Amazon.com, Inc.', exchange: 'NASDAQ' },
  { ticker: 'META', name: 'Meta Platforms', exchange: 'NASDAQ' },
  { ticker: 'BRK-B', name: 'Berkshire Hathaway', exchange: 'NYSE' },
  { ticker: '0700.HK', name: '騰訊控股 (Tencent)', exchange: 'HKEX' },
  { ticker: '9988.HK', name: '阿里巴巴 (Alibaba)', exchange: 'HKEX' }
];

interface TickerSearchProps {
  value: string;
  onChange: (value: string) => void;
  onSelect?: (suggestion: Suggestion) => void;
  placeholder?: string;
  accentColor?: string;
}

const TickerSearch: React.FC<TickerSearchProps> = ({ value, onChange, onSelect, placeholder = "Enter ticker (e.g. 2330.TW)", accentColor = "blue" }) => {
  const [query, setQuery] = useState(value);
  const [suggestions, setSuggestions] = useState<Suggestion[]>([]);
  const [loading, setLoading] = useState(false);
  const [isOpen, setIsOpen] = useState(false);
  const dropdownRef = useRef<HTMLDivElement>(null);
  const lastProcessedQuery = useRef<string>('');

  useEffect(() => {
    setQuery(value);
  }, [value]);

  useEffect(() => {
    if (query.length < 1) {
      setSuggestions([]);
      setIsOpen(false);
      return;
    }

    // Always filter local stocks first
    const filteredLocal = LOCAL_STOCKS.filter(s => 
      s.ticker.toLowerCase().includes(query.toLowerCase()) || 
      s.name.toLowerCase().includes(query.toLowerCase())
    );

    if (query.length >= 2) {
      setIsOpen(true);
      const timer = setTimeout(() => {
        if (query !== lastProcessedQuery.current) {
          searchWithAI(query, filteredLocal);
          lastProcessedQuery.current = query;
        }
      }, 500);
      return () => clearTimeout(timer);
    } else {
      setSuggestions(filteredLocal);
      setIsOpen(filteredLocal.length > 0);
    }
  }, [query]);

  useEffect(() => {
    const handleClickOutside = (event: PointerEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsOpen(false);
      }
    };
    document.addEventListener('pointerdown', handleClickOutside);
    return () => document.removeEventListener('pointerdown', handleClickOutside);
  }, []);

  const searchWithAI = async (searchTerm: string, localMatches: Suggestion[]) => {
    const apiKey = process.env.API_KEY;

    // If no API Key, just use local matches
    if (!apiKey || apiKey === 'undefined' || apiKey === '') {
      setSuggestions(localMatches);
      return;
    }

    setLoading(true);
    try {
      const ai = new GoogleGenAI({ apiKey });
      const prompt = `Search for 5 stock symbols matching "${searchTerm}". 
      Prefer Yahoo Finance formats (e.g., 2330.TW, 0050.TW, AAPL). 
      Return JSON array: [{ticker, name, exchange}]`;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [{ parts: [{ text: prompt }] }],
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                ticker: { type: Type.STRING },
                name: { type: Type.STRING },
                exchange: { type: Type.STRING }
              },
              required: ["ticker", "name", "exchange"]
            }
          }
        }
      });

      const aiResults = JSON.parse(response.text || "[]");

      // Merge results, avoiding duplicates
      const seen = new Set(localMatches.map(s => s.ticker));
      const merged = [...localMatches];
      aiResults.forEach((s: Suggestion) => {
        if (!seen.has(s.ticker)) {
          merged.push(s);
          seen.add(s.ticker);
        }
      });

      setSuggestions(merged);
    } catch (err) {
      // Fail silently and keep local matches
      setSuggestions(localMatches);
    } finally {
      setLoading(false);
    }
  };

  const selectSuggestion = (e: React.PointerEvent, s: Suggestion) => {
    e.preventDefault();
    e.stopPropagation();
    setQuery(s.ticker);
    onChange(s.ticker);
    if (onSelect) onSelect(s);
    setIsOpen(false);
  };

  const ringClass = accentColor === 'emerald' ? 'focus:ring-emerald-500' : 'focus:ring-blue-500';

  return (
    <div className="relative w-full" ref={dropdownRef}>
      <div className="relative">
        <Tag className="absolute left-3 top-3 text-slate-400" size={18} />
        <input 
          type="text"
          placeholder={placeholder}
          value={query}
          onChange={(e) => {
            setQuery(e.target.value);
            onChange(e.target.value);
          }}
          onFocus={() => query.length > 0 && setIsOpen(true)}
          className={`w-full pl-10 pr-10 py-2.5 border border-slate-200 rounded-lg focus:ring-2 ${ringClass} outline-none transition-all text-base bg-white shadow-sm`}
        />
        <div className="absolute right-3 top-3.5">
          {loading ? (
            <Loader2 size={18} className="animate-spin text-blue-500" />
          ) : (
            <Search size={18} className="text-slate-300" />
          )}
        </div>
      </div>

      {isOpen && suggestions.length > 0 && (
        <div className="absolute left-0 right-0 z-[100] mt-2 bg-white border border-slate-200 rounded-xl shadow-2xl overflow-hidden max-h-[280px] overflow-y-auto">
          {suggestions.map((s, idx) => (
            <div
              key={idx}
              onPointerDown={(e) => selectSuggestion(e, s)}
              className="w-full text-left px-5 py-4 hover:bg-slate-50 active:bg-slate-100 flex items-center justify-between border-b border-slate-50 last:border-0 cursor-pointer"
            >
              <div className="flex flex-col min-w-0">
