import React, { useState, useEffect, useRef } from 'react';
import { GoogleGenAI, Type } from "@google/genai";
import { Search, Tag, Check, HelpCircle, Loader2, Globe } from 'lucide-react';

export interface Suggestion {
  ticker: string;
  name: string;
  exchange: string;
}

const LOCAL_STOCKS: Suggestion[] = [
  { ticker: '2330.TW', name: '台積電 (TSMC)', exchange: 'TWSE' },
  { ticker: '0050.TW', name: '元大台灣50', exchange: 'TWSE' },
  { ticker: '2317.TW', name: '鴻海 (Foxconn)', exchange: 'TWSE' },
  { ticker: 'AAPL', name: 'Apple Inc.', exchange: 'NASDAQ' },
  { ticker: 'TSLA', name: 'Tesla, Inc.', exchange: 'NASDAQ' },
  { ticker: 'NVDA', name: 'NVIDIA Corporation', exchange: 'NASDAQ' }
];

interface TickerSearchProps {
  value: string;
  onChange: (value: string) => void;
  onSelect?: (suggestion: Suggestion) => void;
  placeholder?: string;
  accentColor?: string;
}

const TickerSearch: React.FC<TickerSearchProps> = ({ value, onChange, onSelect, placeholder = "Search ticker or name...", accentColor = "blue" }) => {
  const [query, setQuery] = useState(value);
  const [suggestions, setSuggestions] = useState<Suggestion[]>([]);
  const [loading, setLoading] = useState(false);
  const [isOpen, setIsOpen] = useState(false);
  const dropdownRef = useRef<HTMLDivElement>(null);
  const lastProcessedQuery = useRef<string>('');

  useEffect(() => {
    setQuery(value);
  }, [value]);

  useEffect(() => {
    if (query.length < 1) {
      setSuggestions([]);
      setIsOpen(false);
      return;
    }

    // Filter local first for instant response
    const filteredLocal = LOCAL_STOCKS.filter(s => 
      s.ticker.toLowerCase().includes(query.toLowerCase()) || 
      s.name.toLowerCase().includes(query.toLowerCase())
    );

    if (query.length >= 2) {
      setIsOpen(true);
      const timer = setTimeout(() => {
        if (query !== lastProcessedQuery.current) {
          searchWithAI(query, filteredLocal);
          lastProcessedQuery.current = query;
        }
      }, 600);
      return () => clearTimeout(timer);
    } else {
      setSuggestions(filteredLocal);
      setIsOpen(filteredLocal.length > 0);
    }
  }, [query]);

  const searchWithAI = async (searchTerm: string, localMatches: Suggestion[]) => {
    const apiKey = process.env.API_KEY;

    // Fallback if no API key
    if (!apiKey || apiKey === 'undefined') {
      setSuggestions(localMatches);
      return;
    }

    setLoading(true);
    try {
      const ai = new GoogleGenAI({ apiKey });
      const prompt = `Find 5 stock tickers matching "${searchTerm}". Support US (AAPL), TW (2330.TW), HK (0700.HK). Return JSON: [{ticker, name, exchange}]`;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [{ parts: [{ text: prompt }] }],
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                ticker: { type: Type.STRING },
                name: { type: Type.STRING },
                exchange: { type: Type.STRING }
              },
              required: ["ticker", "name", "exchange"]
            }
          }
        }
      });

      const aiResults = JSON.parse(response.text || "[]");
      const seen = new Set(localMatches.map(s => s.ticker));
      const merged = [...localMatches];

      aiResults.forEach((s: Suggestion) => {
        if (!seen.has(s.ticker)) {
          merged.push(s);
          seen.add(s.ticker);
        }
      });

      setSuggestions(merged);
    } catch (err) {
      setSuggestions(localMatches); // Silent fail to local
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    const handleClickOutside = (event: PointerEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsOpen(false);
      }
    };
    document.addEventListener('pointerdown', handleClickOutside);
    return () => document.removeEventListener('pointerdown', handleClickOutside);
  }, []);

  const selectSuggestion = (e: React.PointerEvent, s: Suggestion) => {
    e.preventDefault();
    e.stopPropagation();
    setQuery(s.ticker);
    onChange(s.ticker);
    if (onSelect) onSelect(s);
    setIsOpen(false);
  };

  const ringClass = accentColor === 'emerald' ? 'focus:ring-emerald-500' : 'focus:ring-blue-500';

  return (
    <div className="relative w-full" ref={dropdownRef}>
      <div className="relative">
        <Tag className="absolute left-3 top-3 text-slate-400" size={18} />
        <input 
          type="text"
          autoComplete="off"
          placeholder={placeholder}
          value={query}
          onChange={(e) => {
            const val = e.target.value.toUpperCase();
            setQuery(val);
            onChange(val);
          }}
          onFocus={() => query.length > 0 && setIsOpen(true)}
          className={`w-full pl-10 pr-10 py-2.5 border border-slate-200 rounded-lg focus:ring-2 ${ringClass} outline-none transition-all text-base bg-white shadow-sm font-medium`}
        />
        <div className="absolute right-3 top-3.5 flex items-center space-x-2">
          {loading ? (
            <Loader2 size={16} className="animate-spin text-blue-500" />
          ) : (
            <Search size={18} className="text-slate-300" />
          )}
        </div>
      </div>

      {isOpen && suggestions.length > 0 && (
        <div className="absolute left-0 right-0 z-[100] mt-2 bg-white border border-slate-200 rounded-xl shadow-2xl overflow-hidden animate-in fade-in slide-in-from-top-2 duration-150">
          <div className="max-h-[280px] overflow-y-auto overscroll-contain">
            {suggestions.map((s, idx) => (
              <div
                key={idx}
                onPointerDown={(e) => selectSuggestion(e, s)}
                className="w-full text-left px-5 py-3.5 hover:bg-slate-50 active:bg-slate-100 flex items-center justify-between border-b border-slate-50 last:border-0 cursor-pointer"
              >
                <div className="flex flex-col min-w-0">
                  <span className="font-bold text-slate-900 text-sm tracking-tight">{s.ticker}</span>
                  <span className="text-[10px] text-slate-400 truncate font-medium">{s.name}</span>
                </div>
                <div className="flex flex-col items-end">
                  <span className="text-[9px] font-bold text-slate-300 uppercase tracking-tighter">{s.exchange}</span>
                  {value === s.ticker && <Check size={14} className="text-emerald-500 mt-1" />}
                </div>
              </div>
            ))}
          </div>
          <div className="px-5 py-2.5 bg-slate-50 border-t border-slate-100 flex items-center justify-between text-[10px] text-slate-400 font-medium">
            <div className="flex items-center">
              <Globe size={10} className="mr-1 text-blue-400" />
              <span>Smart Lookup Active</span>
            </div>
            <span className="italic">Manual entry supported</span>
          </div>
        </div>
      )}
    </div>
  );
};

